mapper.select:
SELECT COALESCE(SUM(point), 0)
FROM point
WHERE memberUid = #{memberUid}

mapper.update:
UPDATE `member`
SET pointBalance = (
    SELECT COALESCE(SUM(p.point), 0)
    FROM point p
    WHERE p.memberUid = #{memberUid}
)
WHERE uid = #{memberUid}

mapper.select:
SELECT * FROM `point`
WHERE memberUid = #{memberUid}
  AND content = '적립'        ORDER BY pointNo DESC
    LIMIT #{limit}
